module RefModule(
    input [7:0] a,
    input [7:0] b,
    input clk,
    input rst,
    output reg [8:0] sum
);reg [8:0] obf_carry;

always @ (posedge clk) begin
    if (rst) begin
        sum <= 0;
        obf_carry <= 0;
    end else begin
        {obf_carry, sum} <= a + b + obf_carry;
    end
end

endmodule
